/* --------------------------------------------------------------------------
   HydrationCalculator — live target + cylinder + pee scale
   -------------------------------------------------------------------------- */
const PEE = [
  { c: "#7a5a14", label: "Very dark", fb: "Under-hydrated. Increase water now.", tone: "bad", fill: 24 },
  { c: "#a07d1f", label: "Dark", fb: "Under-hydrated. Drink more water.", tone: "bad", fill: 40 },
  { c: "#caa531", label: "Amber", fb: "Slightly low. Top up through the day.", tone: "warn", fill: 56 },
  { c: "#e6d873", label: "Straw", fb: "On target — pale straw is ideal.", tone: "good", fill: 80 },
  { c: "#f3eeb6", label: "Pale", fb: "On target — well hydrated.", tone: "good", fill: 90 },
  { c: "#fbfaf0", label: "Clear", fb: "Slightly over. You can ease off a little.", tone: "warn", fill: 100 },
];
function HydrationCalculator() {
  const [unit, setUnit] = useState("lb");
  const [w, setW] = useState("160");
  const [pee, setPee] = useState(3);
  const num = parseFloat(w);
  const lbs = unit === "lb" ? num : num * 2.20462;
  const oz = Number.isFinite(lbs) ? Math.round(lbs / 2) : 0;
  const liters = oz ? (oz * 0.0295735).toFixed(1) : "0";
  const fillH = PEE[pee].fill;
  const dehydrated = pee <= 2;
  const barGrad = dehydrated
    ? "linear-gradient(180deg, var(--accent-warn-bright), var(--accent-warn))"
    : "linear-gradient(180deg, var(--accent-primary-bright), var(--accent-primary))";
  return (
    <div className="fp-hydro">
      <div className="fp-hydro__calc">
        <div className="fp-hydro__inrow">
          <label>YOUR BODYWEIGHT</label>
          <div className="fp-hydro__input">
            <input type="number" inputMode="decimal" value={w} onChange={(e) => setW(e.target.value)} min="0" />
            <div className="fp-hydro__unit">
              <button className={unit === "lb" ? "is-on" : ""} onClick={() => setUnit("lb")}>lb</button>
              <button className={unit === "kg" ? "is-on" : ""} onClick={() => setUnit("kg")}>kg</button>
            </div>
          </div>
        </div>
        <div className="fp-hydro__out">
          <span className="fp-hydro__big">{oz}</span>
          <span className="fp-hydro__unitlbl">oz / day</span>
          <span className="fp-hydro__sub">≈ {liters} L — spread across the day, not all at once</span>
        </div>
        <div className="fp-hydro__scale">
          <span className="fp-hydro__scalelbl">THE PEE METHOD — tap your current shade</span>
          <div className="fp-hydro__swatches">
            {PEE.map((s, i) => (
              <button key={i} className={"fp-hydro__sw" + (pee === i ? " is-on" : "")}
                style={{ background: s.c }} onClick={() => setPee(i)} aria-label={s.label} />
            ))}
          </div>
          <p className={"fp-hydro__fb fp-hydro__fb--" + PEE[pee].tone}>{PEE[pee].fb}</p>
        </div>
      </div>
      <div className="fp-hydro__cyl">
        <div className="fp-hydro__tube">
          <div className="fp-hydro__mark" style={{ bottom: "80%" }}><span>ideal</span></div>
          <div className="fp-hydro__fill" style={{ height: fillH + "%", background: barGrad }} />
        </div>
        <div className="fp-hydro__status">{PEE[pee].label.toUpperCase()}</div>
      </div>
    </div>
  );
}

