/* --------------------------------------------------------------------------
   HabitTracker — persistent (window.storage) weekly grid + dial + trend
   -------------------------------------------------------------------------- */
const HABIT_ROWS = [
  { icon: "head", label: "Tongue posture + nose breathing" },
  { icon: "droplet", label: "Water target (pee check light)" },
  { icon: "nose", label: "Mouth tape applied" },
  { icon: "sparkle", label: "Skincare AM / PM" },
  { icon: "camera", label: "Weekly progress photo" },
];
const DAYS = ["M", "T", "W", "T", "F", "S", "S"];
const STORE_KEY = "frame_tracker_v1";

function HabitTracker() {
  const [grid, setGrid] = useState(null); // null = loading
  const [err, setErr] = useState(false);

  useEffect(() => {
    let live = true;
    (async () => {
      try {
        const res = await window.storage.get(STORE_KEY, false);
        if (!live) return;
        if (res && res.value) setGrid(JSON.parse(res.value));
        else setGrid(blank());
      } catch (e) {
        if (live) setGrid(blank());
      }
    })();
    return () => { live = false; };
  }, []);

  function blank() {
    return HABIT_ROWS.map(() => DAYS.map(() => false));
  }
  async function persist(next) {
    setGrid(next);
    try {
      await window.storage.set(STORE_KEY, JSON.stringify(next), false);
      setErr(false);
    } catch (e) { setErr(true); }
  }
  function toggle(r, d) {
    if (!grid) return;
    const next = grid.map((row, ri) => row.map((v, di) => (ri === r && di === d ? !v : v)));
    persist(next);
  }
  async function reset() { await persist(blank()); }

  if (!grid) {
    return <div className="fp-track fp-track--loading">Loading your tracker…</div>;
  }

  const total = grid.flat().filter(Boolean).length;
  const maxCells = HABIT_ROWS.length * DAYS.length;
  const pct = Math.round((total / maxCells) * 100);
  // trend: completed per day (used as a simple "consistency" line)
  const perDay = DAYS.map((_, d) => grid.reduce((a, row) => a + (row[d] ? 1 : 0), 0));

  return (
    <div className="fp-track">
      <div className="fp-track__top">
        <Dial value={total} pct={pct} />
        <Trend perDay={perDay} max={HABIT_ROWS.length} />
      </div>
      <div className="fp-track__gridwrap">
        <table className="fp-track__grid">
          <thead>
            <tr><th className="fp-track__rowhead"> </th>{DAYS.map((d, i) => <th key={i}>{d}</th>)}</tr>
          </thead>
          <tbody>
            {HABIT_ROWS.map((row, r) => (
              <tr key={r}>
                <td className="fp-track__rowhead"><span className="fp-track__ic"><Icon name={row.icon} /></span>{row.label}</td>
                {DAYS.map((_, d) => (
                  <td key={d}>
                    <button className={"fp-track__cell" + (grid[r][d] ? " is-on" : "")}
                      onClick={() => toggle(r, d)} aria-label={`${row.label} day ${d + 1}`}>
                      {grid[r][d] && <Icon name="check" />}
                    </button>
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div className="fp-track__foot">
        <button className="fp-track__reset" onClick={reset}><Icon name="reset" /> RESET WEEK</button>
        <span className="fp-track__save">{err ? "Saved locally only" : "Saved automatically"}</span>
      </div>
    </div>
  );
}
function Dial({ value, pct }) {
  const R = 30, C = 2 * Math.PI * R;
  return (
    <div className="fp-dial">
      <svg viewBox="0 0 80 80">
        <circle cx="40" cy="40" r={R} className="fp-dial__bg" />
        <circle cx="40" cy="40" r={R} className="fp-dial__fg"
          strokeDasharray={C} strokeDashoffset={C * (1 - pct / 100)} transform="rotate(-90 40 40)" />
      </svg>
      <div className="fp-dial__center"><b>{value}</b><i>checks</i></div>
    </div>
  );
}
function Trend({ perDay, max }) {
  const w = 150, h = 56, n = perDay.length;
  const pts = perDay.map((v, i) => {
    const x = (i / (n - 1)) * (w - 8) + 4;
    const y = h - 6 - (v / max) * (h - 14);
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  });
  return (
    <div className="fp-trend">
      <span className="fp-trend__lbl">DAILY CONSISTENCY</span>
      <svg viewBox={`0 0 ${w} ${h}`} preserveAspectRatio="none">
        <polyline className="fp-trend__line" points={pts.join(" ")} />
        {perDay.map((v, i) => {
          const x = (i / (n - 1)) * (w - 8) + 4;
          const y = h - 6 - (v / max) * (h - 14);
          return <circle key={i} cx={x} cy={y} r="2.4" className="fp-trend__dot" />;
        })}
      </svg>
    </div>
  );
}

/* --------------------------------------------------------------------------
   FAQAccordion — category tabs + search + accordion
   -------------------------------------------------------------------------- */
function FAQAccordion({ faqs }) {
  const cats = useMemo(() => ["ALL", ...Array.from(new Set(faqs.map((f) => f.category)))], [faqs]);
  const [cat, setCat] = useState("ALL");
  const [q, setQ] = useState("");
  const [open, setOpen] = useState(-1);
  const filtered = faqs.filter((f) => {
    const inCat = cat === "ALL" || f.category === cat;
    const s = q.trim().toLowerCase();
    const inQ = !s || f.q.toLowerCase().includes(s) || f.a.toLowerCase().includes(s);
    return inCat && inQ;
  });
  const shortCat = (c) => c.replace(/\s*\(.*?\)\s*/g, "").trim();
  return (
    <div className="fp-faq">
      <div className="fp-faq__search">
        <Icon name="search" />
        <input value={q} onChange={(e) => { setQ(e.target.value); setOpen(-1); }} placeholder="Search all questions…" />
        {q && <button onClick={() => setQ("")} aria-label="Clear"><Icon name="x" /></button>}
      </div>
      <div className="fp-faq__tabs">
        {cats.map((c) => (
          <button key={c} className={"fp-faq__tab" + (cat === c ? " is-on" : "")} onClick={() => { setCat(c); setOpen(-1); }}>
            {c === "ALL" ? "ALL" : shortCat(c)}
          </button>
        ))}
      </div>
      <div className="fp-faq__list">
        {filtered.length === 0 && <p className="fp-faq__empty">No questions match “{q}”. Try another term.</p>}
        {filtered.map((f, i) => (
          <div key={i} className={"fp-faq__item" + (open === i ? " is-open" : "")}>
            <button className="fp-faq__q" onClick={() => setOpen(open === i ? -1 : i)}>
              <span>{f.q}</span><Icon name={open === i ? "minus" : "plus"} />
            </button>
            {open === i && (
              <div className="fp-faq__a">
                <span className="fp-faq__cat">{shortCat(f.category)}</span>
                <p><RichText text={f.a} /></p>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

